import React from "react";
import { ArrowRight } from "./icons";

const PromoBanners = () => (
 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 px-12 pt-12 pb-8 max-w-[1600px] mx-auto">

  {/* Featured Story: The Sourdough Method */}
  <div className="relative h-[360px] lg:col-span-2 group overflow-hidden border border-border-light animate-reveal bg-bg-parchment">
   <div className="absolute inset-x-0 bottom-0 h-2/3 bg-gradient-to-t from-black/20 to-transparent pointer-events-none" />

   <div className="relative h-full p-12 flex flex-col justify-between z-10">
    <div>
     <span className="inline-block border border-accent-gold text-accent-gold text-[10px] font-black uppercase tracking-[0.2em] px-3 py-1 mb-6">Our Process</span>
     <h2 className="text-[44px] font-heading font-black leading-[1.05] tracking-tight text-fg-main max-w-[450px]">
      THE ART OF SLOW FERMENTATION
     </h2>
     <p className="text-[14px] text-fg-soft mt-4 font-medium max-w-[320px] leading-relaxed">
      We believe in 48-hour patience. Every loaf is hand-scored and stone-baked for the perfect crust.
     </p>
    </div>

    <button className="btn-boutique w-fit mt-8 group/btn">
     Explore the technique <ArrowRight size={16} className="ml-3 group-hover/btn:translate-x-1 transition-transform" />
    </button>
   </div>

   <div className="absolute right-[-10%] top-[-10%] w-[60%] h-[120%] opacity-20 bg-accent-gold blur-[120px] pointer-events-none" />
  </div>

  {/* Secondary Spotlight: Seasonal */}
  <div className="relative h-[360px] group overflow-hidden border border-border-light animate-reveal bg-[#121212]">
   <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] pointer-events-none" />

   <div className="relative h-full p-10 flex flex-col justify-between z-10">
    <div>
     <span className="text-white/40 text-[10px] font-black uppercase tracking-[0.2em] mb-4 block">Limited Edition</span>
     <h2 className="text-[32px] font-heading font-bold leading-tight text-white mb-4">
      WINTER<br />HARVEST<br />BOX
     </h2>
     <div className="w-12 h-[1px] bg-accent-gold" />
    </div>

    <div className="flex items-center justify-between mt-auto">
     <span className="text-[13px] font-bold text-white/60 uppercase tracking-widest">Shop the drop</span>
     <div className="w-12 h-12 rounded-full border border-white/20 flex items-center justify-center text-white group-hover:bg-accent-gold group-hover:border-accent-gold transition-all duration-500">
      <ArrowRight size={18} />
     </div>
    </div>
   </div>
  </div>

 </div>
);

export default PromoBanners;
